func dailyTemperatures(_ temperatures: [Int]) -> [Int] {
    var daysToWait = Array(repeating: 0, count: temperatures.count)
    var colderDaysStack: [(temperature: Int, index: Int)] = []
    // Iterate through each day's temperature.
    for (currentIndex, currentTemperature) in temperatures.enumerated() {
        // While there are colder days on the stack and the current temperature is warmer.
        while let lastColderDay = colderDaysStack.last, currentTemperature > lastColderDay.temperature {
            // Calculate the number of days passed since the last colder day.
            let daysDifference = currentIndex - lastColderDay.index
            daysToWait[lastColderDay.index] = daysDifference
            // Remove the processed colder day from the stack.
            colderDaysStack.removeLast()
        }
        // Add the current day to the stack as a potential colder day for future days.
        colderDaysStack.append((currentTemperature, currentIndex))
    }
    return daysToWait
}
